// Chatwoot's message_created payload shape — spot-check field names against a real delivery.
const body = $input.first().json.body || $input.first().json;
const clientId = body.client_id || body.account_id || '';
const leadId = body.lead_id || body.conversation?.contact_inbox?.contact_id || '';
const messageText = body.content || body.message?.content || '';
const conversationId = body.conversation?.id || body.conv_id || '';

if (!clientId || !leadId || !messageText) {
  throw new Error('Missing client_id, lead_id, or message content in webhook payload — check the payload shape against Chatwoot\'s actual message_created schema.');
}
return [{ json: { clientId: String(clientId), leadId: String(leadId), messageText, conversationId } }];

const client = $input.first().json;
const parsed = $('Code · Parse Incoming Message').first().json;
const leadsTableId = client.leads_table_id || client.LEADS_TABLE_ID || '';
if (!leadsTableId) throw new Error('This client has no leads_table_id configured.');
return [{ json: { ...parsed, client, leadsTableId } }];

const lead = $input.first().json;
const prior = $('Code · Resolve Leads Table').first().json;
let prefs = {};
try { prefs = JSON.parse(lead.ecom_prefs || '{}'); } catch (e) { prefs = {}; }
const STALE_MS = 6 * 3600 * 1000; // see SETUP.md "Ecom bot memory" for why 6h
const isStale = !prefs.updated_at || (Date.now() - new Date(prefs.updated_at).getTime()) > STALE_MS;
if (isStale) prefs = {};
return [{ json: { ...prior, lead, prefs } }];

const d = $('Code · Build Slot-Extraction Prompt').first().json;
const aiResp = $input.first().json;
let extracted = {};
try {
  const raw = aiResp.choices?.[0]?.message?.content || '{}';
  extracted = JSON.parse((raw.match(/\{[\s\S]*\}/) || ['{}'])[0]);
} catch (e) { extracted = {}; }

const merged = {
  size: extracted.size || d.prefs.size || null,
  color: extracted.color || d.prefs.color || null,
  category: extracted.category || d.prefs.category || null,
  budget_max: extracted.budget_max ?? d.prefs.budget_max ?? null,
  language: extracted.language || d.prefs.language || 'en',
  last_sku: d.prefs.last_sku || null,
  last_product_name: d.prefs.last_product_name || null,
};

let ecomIds = {};
try { ecomIds = JSON.parse(d.client.ecom_table_ids || '{}'); } catch (e) {}
const productsTableId = ecomIds.products || 'mjlc2vi6iqbp87c';

// Same clause-building rules as handleEcomList in cloudflare-worker/worker.js — kept in sync
// deliberately, see SETUP.md.
function sanitize(v) { return String(v).replace(/[(),~]/g, '').trim(); }
const clauses = [`(client_id,eq,${d.client.Id})`, '(status,neq,inactive)'];
if (merged.color) clauses.push(`(color,like,${sanitize(merged.color)})`);
if (merged.category) clauses.push(`(category,like,${sanitize(merged.category)})`);
if (merged.size) clauses.push(`(size,eq,${sanitize(merged.size)})`);
if (merged.budget_max) clauses.push(`(price,lte,${parseFloat(merged.budget_max) || 0})`);

return [{ json: { ...d, merged, productsTableId, whereClause: clauses.join('~and') } }];

const d = $('Code · Merge Slots + Resolve Products Table').first().json;
const items = $input.all();
const products = items.map(i => i.json).slice(0, 5);
const merged = { ...d.merged };

if (products.length === 1) {
  merged.last_sku = products[0].sku || merged.last_sku;
  merged.last_product_name = products[0].name || merged.last_product_name;
}
merged.updated_at = new Date().toISOString();

const storeName = d.client.client_name || 'our store';
const contact = d.client.support_phone || d.client.review_link || d.client.authentik_email || 'us on WhatsApp';

const productBlock = products.length
  ? products.map(p => `- ${p.name} | SKU ${p.sku || 'N/A'} | Color: ${p.color || '—'} | Size: ${p.size || '—'} | ${p.currency || 'AED'} ${p.price} | ${p.stock > 0 ? 'In stock' : 'Out of stock'}${p.image_url ? ' | ' + p.image_url : ''}`).join('\n')
  : "NONE — no products currently match this customer's stated preferences.";

const prefsBlock = Object.entries(merged).filter(([k, v]) => v && k !== 'updated_at' && k !== 'last_sku' && k !== 'last_product_name').map(([k, v]) => `${k}: ${v}`).join(', ') || 'none yet';

const systemPrompt = `You are the WhatsApp shopping assistant for ${storeName}. Support contact: ${contact}.

STRICT RULES:
1. You may ONLY describe, recommend, or quote prices/sizes/colors for products listed under MATCHED PRODUCTS below. Never invent a product, price, size, color, or link that isn't in that list.
2. If MATCHED PRODUCTS is NONE, say so honestly and offer to check with ${storeName} directly (${contact}) instead of making something up.
3. Remembered preferences for this customer so far: ${prefsBlock}. Do not ask again for anything already listed there — only ask about what's still missing (e.g. if size is known but color isn't, ask for color only).
4. Always reply in this customer's language: ${merged.language}. Never switch language mid-conversation.
5. Use the same reply format every time a product is shown: Name, Price, Size, Color, Link, then one short question that moves the sale forward.
6. If a product image is being sent as an attachment separately, don't repeat its link in your text — just write the caption-style reply.

MATCHED PRODUCTS:
${productBlock}

Customer's message: "${d.messageText}"`;

return [{ json: { ...d, merged, products, systemPrompt } }];

const d = $('Code · Build Anti-Hallucination Prompt').first().json;
const aiResp = $input.first().json;
const replyText = aiResp.choices?.[0]?.message?.content || "Sorry, I couldn't process that — let me get a team member to help.";

// Only attach an image when there's exactly one confidently-matched product — sending a
// possibly-wrong photo for an ambiguous multi-match list is worse than no photo at all.
let driveFileId = null;
if (d.products.length === 1 && d.products[0].image_url) {
  const url = d.products[0].image_url;
  if (/drive\.google\.com/.test(url)) {
    // Two independent shapes rather than one combined pattern: /file/d/{id}/... (the "share"
    // link format) and ?id={id} anywhere in the query string (open?id=, uc?id=, uc?export=
    // download&id=, thumbnail?id=, etc. — id can be the first or a later query param either way).
    const pathMatch = url.match(/\/file\/d\/([a-zA-Z0-9_-]+)/);
    const queryMatch = url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
    driveFileId = pathMatch?.[1] || queryMatch?.[1] || null;
  }
}

return [{ json: { ...d, replyText, driveFileId, hasDriveImage: !!driveFileId } }];
